import { useState, useEffect, useRef, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { useSmartBack } from "@/hooks/useSmartBack";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { ArrowLeft, Instagram, Loader2, ThumbsUp, ThumbsDown, Share2, MessageSquare, Play, X } from "lucide-react";
import IChingSection from "@/components/IChingSection";
import { useStoryReactions } from "@/hooks/useStoryReactions";
import { useAuth } from "@/contexts/AuthContext";
import { useComments } from "@/hooks/useComments";
import RestaurantComments from "@/components/RestaurantComments";
import DislikeReasonDialog from "@/components/DislikeReasonDialog";
import { toast } from "sonner";

const AboutUs = () => {
  const { t, i18n } = useTranslation();
  const [isAutoTranslating, setIsAutoTranslating] = useState(false);
  const goBack = useSmartBack("/");
  const [richContent, setRichContent] = useState<string | null>(null);
  const [ichingText, setIchingText] = useState<string | null>(null);
  const [confessionVideoUrl, setConfessionVideoUrl] = useState<string | null>(null);
  const [showVideo, setShowVideo] = useState(false);
  const [autoTranslated, setAutoTranslated] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [readProgress, setReadProgress] = useState(0);
  const [showScrollTop, setShowScrollTop] = useState(false);
  const [contentId, setContentId] = useState<string | null>(null);
  const [showComments, setShowComments] = useState(false);
  const [showDislikeDialog, setShowDislikeDialog] = useState(false);
  const autoAttempted = useRef(false);
  const lastLang = useRef(i18n.language);
  const contentRef = useRef<HTMLDivElement>(null);

  const { user } = useAuth();
  const { counts, userReaction, toggleReaction } = useStoryReactions(contentId || undefined, "about_us");
  const { data: commentsData } = useComments(contentId || "", "about_us", { enabled: !!contentId });
  const commentsCount = commentsData?.reduce((acc: number, c: any) => acc + 1 + (c.replies?.length || 0), 0) || 0;

  // Reading progress & scroll-to-top visibility
  useEffect(() => {
    const handleScroll = () => {
      const scrollTop = window.scrollY;
      const docHeight = document.documentElement.scrollHeight - window.innerHeight;
      if (docHeight > 0) {
        setReadProgress(Math.min(100, (scrollTop / docHeight) * 100));
      }
      setShowScrollTop(scrollTop > 400);
    };
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const scrollToTop = useCallback(() => {
    window.scrollTo({ top: 0, behavior: "smooth" });
  }, []);

  // Fetch content from database
  useEffect(() => {
    autoAttempted.current = false;
    lastLang.current = i18n.language;
    setAutoTranslated(null);

    const fetchContent = async () => {
      setLoading(true);
      const { data } = await supabase
        .from("about_us_content")
        .select("*")
        .limit(1)
        .single();

      if (data) {
        setContentId(data.id);
        const content = data.content_zh;
        if (content && content.trim() && content !== "<p><br></p>") {
          setRichContent(content);
        } else {
          setRichContent(null);
        }
        setIchingText((data as any).iching_text || null);
        setConfessionVideoUrl((data as any).confession_video_url || null);
      }
      setLoading(false);
    };
    fetchContent();
  }, [i18n.language]);

  // Auto-translate main content to user's language
  useEffect(() => {
    if (autoAttempted.current) return;
    if (!richContent || loading) return;

    const userLang = i18n.language;
    if (userLang.startsWith("zh")) return;

    autoAttempted.current = true;
    setIsAutoTranslating(true);
    const doTranslate = async () => {
      try {
        const { data, error } = await supabase.functions.invoke("translate-content", {
          body: { text: richContent, targetLang: userLang },
        });
        if (!error && data?.translatedText) {
          setAutoTranslated(data.translatedText);
        }
      } catch {}
      setIsAutoTranslating(false);
    };
    doTranslate();
  }, [richContent, loading, i18n.language]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  const displayContent = autoTranslated || richContent;
  const showTranslatingHint = isAutoTranslating && !autoTranslated;

  if (!displayContent && !ichingText) {
    return (
      <div className="min-h-screen pt-4 pb-12 px-4 bg-background">
        <div className="container mx-auto max-w-3xl">
          <div className="flex items-center justify-between mb-6">
            <Button variant="ghost" size="icon" onClick={goBack} className="h-10 w-10 rounded-md bg-background shadow-sm border border-border/50">
              <ArrowLeft className="h-5 w-5" />
            </Button>
          </div>
          <h1 className="text-3xl font-bold text-foreground mb-4">{t("aboutUs.title")}</h1>
          <p className="text-muted-foreground">{t("aboutUs.intro")}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background" ref={contentRef}>
      {/* Reading progress bar */}
      <div className="fixed top-0 left-0 right-0 z-50 h-[3px] bg-muted/30">
        <div
          className="h-full bg-primary/70 transition-[width] duration-150 ease-out"
          style={{ width: `${readProgress}%` }}
        />
      </div>

      {/* Sticky header */}
      <div className="sticky top-0 z-40 bg-background/80 backdrop-blur-md border-b border-border/30">
        <div className="container mx-auto max-w-3xl px-4 py-3 flex items-center justify-between">
          <Button variant="ghost" size="icon" onClick={goBack} className="h-9 w-9 rounded-md">
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <span className="text-sm font-medium text-foreground/70 truncate mx-4">
            {t("aboutUs.title")}
          </span>
          <a
            href="https://www.instagram.com/xiaoxiongmarket/"
            target="_blank"
            rel="noopener noreferrer"
            className="h-9 w-9 rounded-md flex items-center justify-center text-muted-foreground hover:text-foreground active:bg-secondary transition-colors"
          >
            <Instagram className="h-4.5 w-4.5" />
          </a>
        </div>
      </div>

      {/* Main content area */}
      <article className="container mx-auto max-w-3xl px-4 pt-8 pb-16">
        {/* Title */}
        <header className="mb-8">
          <h1 className="text-3xl md:text-4xl font-bold text-foreground leading-tight">
            {t("aboutUs.title")}
          </h1>
          <div className="flex items-center gap-4 mt-3">
            <div className="h-1 w-12 rounded-full bg-primary/60" />
            {(counts.likes > 0 || counts.dislikes > 0) && (
              <div className="flex items-center gap-3 text-sm text-muted-foreground">
                {counts.likes > 0 && (
                  <span className="inline-flex items-center gap-1">
                    <ThumbsUp className="w-3.5 h-3.5" /> {counts.likes}
                  </span>
                )}
                {counts.dislikes > 0 && (
                  <span className="inline-flex items-center gap-1">
                    <ThumbsDown className="w-3.5 h-3.5" /> {counts.dislikes}
                  </span>
                )}
              </div>
            )}
          </div>
        </header>

        {/* Translating hint */}
        {showTranslatingHint && (
          <div className="flex items-center gap-2 mb-6 text-sm text-muted-foreground animate-pulse">
            <Loader2 className="h-4 w-4 animate-spin" />
            <span>{t("translate.translating", "翻译中...")}</span>
          </div>
        )}

        {/* Rich content with optimized reading typography */}
        {displayContent && (
          <>
            <div
              className="prose prose-lg max-w-none dark:prose-invert
                prose-headings:text-foreground prose-headings:leading-snug prose-headings:mt-8 prose-headings:mb-4
                prose-p:text-muted-foreground prose-p:leading-relaxed prose-p:mb-5
                prose-a:text-primary prose-a:no-underline hover:prose-a:underline
                prose-strong:text-foreground
                prose-ul:text-muted-foreground prose-ol:text-muted-foreground
                prose-li:mb-1
                prose-img:rounded-lg prose-img:shadow-md
                prose-blockquote:border-primary/40 prose-blockquote:text-muted-foreground/80
                selection:bg-primary/20"
              dangerouslySetInnerHTML={{ __html: displayContent }}
            />

            {/* Confession video button - shown after 【自白】 content */}
            {confessionVideoUrl && (
              <div className="flex justify-center my-6">
                <button
                  onClick={() => setShowVideo(true)}
                  className="group inline-flex items-center gap-2 px-5 py-2.5 rounded-full bg-primary/10 hover:bg-primary/20 text-primary font-medium text-sm transition-all duration-300 active:scale-95 border border-primary/20"
                >
                  <span className="w-8 h-8 rounded-full bg-primary/20 group-hover:bg-primary/30 flex items-center justify-center transition-colors">
                    <Play className="w-4 h-4 fill-primary" />
                  </span>
                  {t("aboutUs.playConfession", "播放自白视频")}
                </button>
              </div>
            )}

            {/* Video modal */}
            {showVideo && confessionVideoUrl && (
              <div
                className="fixed inset-0 z-[100] bg-black/80 flex items-center justify-center p-4"
                onClick={() => setShowVideo(false)}
              >
                <div
                  className="relative w-full max-w-2xl rounded-xl overflow-hidden bg-black shadow-2xl"
                  onClick={(e) => e.stopPropagation()}
                >
                  <button
                    className="absolute top-3 right-3 z-10 w-8 h-8 rounded-full bg-black/60 text-white flex items-center justify-center hover:bg-black/80 transition-colors"
                    onClick={() => setShowVideo(false)}
                  >
                    <X className="w-4 h-4" />
                  </button>
                  <video
                    src={confessionVideoUrl}
                    controls
                    autoPlay
                    className="w-full max-h-[80vh]"
                  />
                </div>
              </div>
            )}
          </>
        )}

        {/* I Ching section */}
        {ichingText && ichingText.trim() && (
          <div className="mt-10 pt-6 border-t border-border/40">
            <IChingSection text={ichingText} />
          </div>
        )}

        {/* Reaction buttons */}
        <div className="flex items-center justify-center gap-4 pt-6 mt-8 border-t border-border/50">
          <button onClick={() => {
            if (!user) { toast.info(t("common.loginRequired", "请先登录")); return; }
            toggleReaction.mutate({ type: "like" });
          }}
            className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
              userReaction === "like" ? "bg-primary/15 text-primary" : "text-muted-foreground hover:text-primary hover:bg-primary/10"
            }`}>
            <ThumbsUp className={`w-4 h-4 ${userReaction === "like" ? "fill-primary" : ""}`} />
            {counts.likes > 0 && <span>{counts.likes}</span>}
          </button>
          <button onClick={() => {
            if (!user) { toast.info(t("common.loginRequired", "请先登录")); return; }
            if (userReaction === "dislike") {
              toggleReaction.mutate({ type: "dislike" });
            } else {
              setShowDislikeDialog(true);
            }
          }}
            className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
              userReaction === "dislike" ? "bg-destructive/15 text-destructive" : "text-muted-foreground hover:text-destructive hover:bg-destructive/10"
            }`}>
            <ThumbsDown className={`w-4 h-4 ${userReaction === "dislike" ? "fill-destructive" : ""}`} />
            {counts.dislikes > 0 && <span>{counts.dislikes}</span>}
          </button>
          <button onClick={async () => {
            try {
              if (navigator.share) {
                await navigator.share({ title: t("aboutUs.title"), url: window.location.href });
              } else if (navigator.clipboard) {
                await navigator.clipboard.writeText(window.location.href);
                toast.success(t("common.copied", "已复制链接"));
              }
            } catch {}
          }}
            className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium text-muted-foreground hover:text-primary hover:bg-primary/10 transition-all duration-200 active:scale-95">
            <Share2 className="w-4 h-4" />
          </button>
          <button onClick={() => setShowComments(!showComments)}
            className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
              showComments ? "bg-primary/15 text-primary" : "text-muted-foreground hover:text-primary hover:bg-primary/10"
            }`}>
            <MessageSquare className="w-4 h-4" />
            {commentsCount > 0 && <span>{commentsCount}</span>}
          </button>
        </div>

        {/* Comments section */}
        {showComments && contentId && (
          <div className="mt-4">
            <RestaurantComments targetId={contentId} targetType="about_us" />
          </div>
        )}
      </article>

      <DislikeReasonDialog
        open={showDislikeDialog}
        onOpenChange={setShowDislikeDialog}
        onSubmit={(reason) => {
          try { toggleReaction.mutate({ type: "dislike", reason }); } catch (e) { console.error(e); }
        }}
      />

    </div>
  );
};

export default AboutUs;
